export const MANA_STAGE_THRESHOLDS = {
  surge: 85,
  high: 60,
  steady: 35,
  low: 15,
} as const;

export type ManaStage = 'surge' | 'high' | 'steady' | 'low' | 'empty';
export type ManaStageClass = `mana-${ManaStage}`;

export function getManaStage(percent: number): ManaStage {
  if (percent >= MANA_STAGE_THRESHOLDS.surge) {
    return 'surge';
  }

  if (percent >= MANA_STAGE_THRESHOLDS.high) {
    return 'high';
  }

  if (percent >= MANA_STAGE_THRESHOLDS.steady) {
    return 'steady';
  }

  if (percent >= MANA_STAGE_THRESHOLDS.low) {
    return 'low';
  }

  return 'empty';
}

export function getManaStateLabel(percent: number) {
  const stage = getManaStage(percent);

  switch (stage) {
    case 'surge':
      return '充盈';
    case 'high':
      return '高涨';
    case 'steady':
      return '稳定';
    case 'low':
      return '低鸣';
    default:
      return '枯竭';
  }
}

export function getManaStageClass(percent: number): ManaStageClass {
  return `mana-${getManaStage(percent)}`;
}
