import type { Schema as StatusSchema } from '../../schema';

export type MagicalGirlRecord = StatusSchema['魔法少女'][string];

type WorldbookEntry = {
  name?: string;
  content?: string;
};

export type PreloadedMagicGirlMeta = {
  trueName: string;
  normalMagicName: string;
  fallenMagicName: string;
};

export type PreloadedMagicGirlCatalog = {
  worldbookName: string | null;
  byTrueName: Record<string, PreloadedMagicGirlMeta>;
  byAlias: Record<string, PreloadedMagicGirlMeta>;
};

const EMPTY_CATALOG: PreloadedMagicGirlCatalog = {
  worldbookName: null,
  byTrueName: {},
  byAlias: {},
};

const PRELOADED_NAME_ALIASES: Record<string, string[]> = {
  小银: ['西娅'],
};

let cachedCatalog = EMPTY_CATALOG;
let cachedCatalogTask: Promise<PreloadedMagicGirlCatalog> | null = null;

function isKnownName(value: unknown): value is string {
  return typeof value === 'string' && value.trim().length > 0 && value.trim() !== '???';
}

function extractMagicName(content: unknown) {
  const text = typeof content === 'string' ? content : '';
  const match = text.match(/^\s*魔法名:\s*(.+)$/m);
  return match?.[1]?.trim() || '';
}

function parseMagicalGirlEntry(entry: WorldbookEntry) {
  if (!isKnownName(entry.name)) {
    return null;
  }

  const match = entry.name.match(/^\[角色\]\s+(.+?)(-堕落魔法少女|-魔法少女)$/);
  if (!match) {
    return null;
  }

  return {
    trueName: match[1].trim(),
    fallen: match[2] === '-堕落魔法少女',
    magicName: extractMagicName(entry.content),
  };
}

function getCurrentWorldbookName() {
  try {
    const worldbookName = _.get(getCharWorldbookNames('current'), 'primary', null);
    return isKnownName(worldbookName) ? worldbookName : null;
  } catch {
    return null;
  }
}

function expandPreloadedAliases(...values: Array<string | null | undefined>) {
  const aliases = new Set<string>();

  values.filter(isKnownName).forEach(value => {
    const trimmed = value.trim();
    aliases.add(trimmed);

    Object.entries(PRELOADED_NAME_ALIASES).forEach(([canonical, extraAliases]) => {
      if (canonical === trimmed || extraAliases.includes(trimmed)) {
        aliases.add(canonical);
        extraAliases.forEach(alias => aliases.add(alias));
      }
    });
  });

  return [...aliases];
}

function buildCatalog(entries: WorldbookEntry[], worldbookName: string | null): PreloadedMagicGirlCatalog {
  const byTrueName: Record<string, PreloadedMagicGirlMeta> = {};
  const byAlias: Record<string, PreloadedMagicGirlMeta> = {};

  entries.forEach(entry => {
    const parsed = parseMagicalGirlEntry(entry);
    if (!parsed) {
      return;
    }

    const current = byTrueName[parsed.trueName] ?? {
      trueName: parsed.trueName,
      normalMagicName: '',
      fallenMagicName: '',
    };

    if (parsed.fallen) {
      current.fallenMagicName = parsed.magicName;
    } else {
      current.normalMagicName = parsed.magicName;
    }

    byTrueName[parsed.trueName] = current;
  });

  Object.values(byTrueName).forEach(role => {
    if (!isKnownName(role.normalMagicName) || !isKnownName(role.fallenMagicName)) {
      return;
    }

    expandPreloadedAliases(role.trueName, role.normalMagicName, role.fallenMagicName).forEach(alias => {
      if (!byAlias[alias]) {
        byAlias[alias] = role;
      }
    });
  });

  return {
    worldbookName,
    byTrueName,
    byAlias,
  };
}

export async function loadPreloadedMagicGirlCatalog(force = false) {
  const worldbookName = getCurrentWorldbookName();
  if (!worldbookName) {
    cachedCatalog = EMPTY_CATALOG;
    return cachedCatalog;
  }

  if (!force && cachedCatalog.worldbookName === worldbookName && Object.keys(cachedCatalog.byTrueName).length) {
    return cachedCatalog;
  }

  if (!force && cachedCatalogTask) {
    return cachedCatalogTask;
  }

  cachedCatalogTask = (async () => {
    try {
      const entries = (await getWorldbook(worldbookName)) as WorldbookEntry[];
      cachedCatalog = buildCatalog(entries, worldbookName);
      return cachedCatalog;
    } catch {
      cachedCatalog = EMPTY_CATALOG;
      return cachedCatalog;
    } finally {
      cachedCatalogTask = null;
    }
  })();

  return cachedCatalogTask;
}

export function resolvePreloadedMagicGirl(catalog: PreloadedMagicGirlCatalog, key: string, girl: MagicalGirlRecord) {
  const aliases = expandPreloadedAliases(key, girl.真名, girl.魔法名);

  for (const alias of aliases) {
    const role = catalog.byAlias[alias];
    if (role) {
      return role;
    }
  }

  return null;
}

export function getVisibleTrueName(girl: MagicalGirlRecord) {
  return girl.暴露 ? girl.真名 : '???';
}

export function getCurrentMagicName(girl: MagicalGirlRecord) {
  return girl.魔法名 || '???';
}

export function getMagicalGirlTypeLabel(girl: MagicalGirlRecord) {
  return girl.是否堕落 ? '堕落魔法少女' : '魔法少女';
}

export function getMagicPercent(current: number, max: number) {
  if (!max) {
    return 0;
  }

  return Math.round((current / max) * 100);
}

export function confirmFall(girl: MagicalGirlRecord) {
  girl.是否堕落 = true;
  girl.精神极限 = false;
}

export function dismissFallRequest(girl: MagicalGirlRecord) {
  girl.精神极限 = false;
}

export function switchDynamicGirlState(girl: MagicalGirlRecord, nextFallen: boolean, nextMagicName: string) {
  const name = nextMagicName.trim();
  if (!name) {
    return false;
  }

  girl.是否堕落 = nextFallen;
  girl.魔法名 = name;
  girl.精神极限 = false;
  return true;
}
